final:
module comparator (
    input [1:0] a,
    input [1:0] b,
    output reg gte,
    output reg eq,
    output reg gt
);

always @(*) begin
    gte = 0;
    eq = 0;
    gt = 0;

    if (a < b) begin
        gte = 1;
    end else if (a == b) begin
        eq = 1;
    end else begin
        gt = 1;
    end
end

endmodule
